// Program.cs
// This file is the entry point of your ASP.NET Core application.
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Configuration;
using SamlApp.Models;
using SamlApp.Services;

var builder = WebApplication.CreateBuilder(args);

// Configure SAML settings from appsettings.json
builder.Services.AddSingleton(provider =>
{
    var configuration = provider.GetRequiredService<IConfiguration>();
    var samlSettings = new SamlSettings();
    configuration.GetSection("SamlSettings").Bind(samlSettings);
    return samlSettings;
});

// Add SAML request service
builder.Services.AddTransient<SamlRequestService>();

// Add services to the container.
builder.Services.AddControllersWithViews();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Home/Error");
    app.UseHsts();
}

app.UseHttpsRedirection();
app.UseStaticFiles();

app.UseRouting();

app.UseAuthorization();

app.MapControllerRoute(
    name: "default",
    pattern: "{controller=Home}/{action=Index}/{id?}"); // Default route

// Map the SSO initiation endpoint
app.MapControllerRoute(
    name: "ssoLogin",
    pattern: "sso/login",
    defaults: new { controller = "Sso", action = "InitiateSso" });

// Map the Assertion Consumer Service endpoint
app.MapControllerRoute(
    name: "samlAcs",
    pattern: "saml/acs",
    defaults: new { controller = "Sso", action = "AssertionConsumerService" });

app.Run();